import React from 'react'

export default function Amenities({allAmenities}) {

    const listItems = allAmenities.map((amenity) => 
        <li key={amenity.toString()}>
            {amenity}
        </li>
    );

  return (
    <>
        <ul>{listItems}</ul>
    </>
  )
}
